import React, { useEffect, useState } from "react";
import axios from "axios";

const Report = () => {
  const [monthlyRevenue, setMonthlyRevenue] = useState([]);
  const [yearlyRevenue, setYearlyRevenue] = useState([]);
  const [topCustomers, setTopCustomers] = useState([]);
  const [roomUsage, setRoomUsage] = useState([]);
  const [viewMode, setViewMode] = useState("monthly"); // "monthly" hoặc "yearly"

  const apiBase = "http://localhost:5000/api/report";

  useEffect(() => {
    fetchRevenue();
    fetchTopCustomers();
    fetchRoomUsage();
  }, []);

  const fetchRevenue = async () => {
    try {
      const res = await axios.get(`${apiBase}/revenue`);
      setMonthlyRevenue(res.data.monthly);
      setYearlyRevenue(res.data.yearly);
    } catch (err) {
      console.error(err);
      alert("Lỗi khi tải báo cáo doanh thu");
    }
  };

  const fetchTopCustomers = async () => {
    try {
      const res = await axios.get(`${apiBase}/topcustomer`);
      setTopCustomers(res.data);
    } catch (err) {
      console.error(err);
      alert("Lỗi khi tải top khách hàng");
    }
  };

  const fetchRoomUsage = async () => {
    try {
      const res = await axios.get(`${apiBase}/roomusage`);
      setRoomUsage(res.data);
    } catch (err) {
      console.error(err);
      alert("Lỗi khi tải công suất phòng");
    }
  };

  const Card = ({ title, children }) => (
    <div className="border rounded-lg shadow p-4 mb-6 bg-white">
      <h2 className="text-lg font-semibold mb-2">{title}</h2>
      {children}
    </div>
  );

  const renderRevenueTable = () => {
    const tableClass =
      "w-full border border-gray-300 rounded-lg overflow-hidden text-sm";
    const thClass =
      "border-b px-4 py-2 font-medium text-left bg-blue-200";
    const tdClass = "border-b px-4 py-2";
    const trOdd = "bg-white";
    const trEven = "bg-blue-50";
    const trHover = "hover:bg-blue-100";

    if (viewMode === "monthly") {
      if (monthlyRevenue.length === 0) return <p className="p-2">Chưa có dữ liệu</p>;

      return (
        <table className={tableClass}>
          <thead>
            <tr>
              <th className={thClass}>Năm</th>
              <th className={thClass}>Tháng</th>
              <th className={thClass}>Doanh thu</th>
            </tr>
          </thead>
          <tbody>
            {monthlyRevenue.map((row, idx) => (
              <tr
                key={idx}
                className={`${idx % 2 === 0 ? trEven : trOdd} ${trHover}`}
              >
                <td className={tdClass}>{row.Nam}</td>
                <td className={tdClass}>{row.Thang}</td>
                <td className={tdClass}>{row.DoanhThu}</td>
              </tr>
            ))}
          </tbody>
        </table>
      );
    } else {
      if (yearlyRevenue.length === 0) return <p className="p-2">Chưa có dữ liệu</p>;

      return (
        <table className={tableClass}>
          <thead>
            <tr>
              <th className={thClass}>Năm</th>
              <th className={thClass}>Doanh thu</th>
            </tr>
          </thead>
          <tbody>
            {yearlyRevenue.map((row, idx) => (
              <tr
                key={idx}
                className={`${idx % 2 === 0 ? trEven : trOdd} ${trHover}`}
              >
                <td className={tdClass}>{row.Nam}</td>
                <td className={tdClass}>{row.DoanhThu}</td>
              </tr>
            ))}
          </tbody>
        </table>
      );
    }
  };

  const renderTopCustomersTable = () => {
    const tableClass =
      "w-full border border-gray-300 rounded-lg overflow-hidden text-sm";
    const thClass =
      "border-b px-4 py-2 font-medium text-left bg-green-200";
    const tdClass = "border-b px-4 py-2";
    const trOdd = "bg-white";
    const trEven = "bg-green-50";
    const trHover = "hover:bg-green-100";

    if (topCustomers.length === 0) return <p>Chưa có dữ liệu</p>;

    return (
      <table className={tableClass}>
        <thead>
          <tr>
            <th className={thClass}>Mã KH</th>
            <th className={thClass}>Họ tên</th>
            <th className={thClass}>Số lần đặt</th>
            <th className={thClass}>Tổng chi tiêu</th>
          </tr>
        </thead>
        <tbody>
          {topCustomers.map((row, idx) => (
            <tr
              key={idx}
              className={`${idx % 2 === 0 ? trEven : trOdd} ${trHover}`}
            >
              <td className={tdClass}>{row.MaKH}</td>
              <td className={tdClass}>{row.HoTen}</td>
              <td className={tdClass}>{row.SoLanDat}</td>
              <td className={tdClass}>{row.TongChiTieu}</td>
            </tr>
          ))}
        </tbody>
      </table>
    );
  };

  const renderRoomUsageTable = () => {
    const tableClass =
      "w-full border border-gray-300 rounded-lg overflow-hidden text-sm";
    const thClass =
      "border-b px-4 py-2 font-medium text-left bg-yellow-200";
    const tdClass = "border-b px-4 py-2";
    const trOdd = "bg-white";
    const trEven = "bg-yellow-50";
    const trHover = "hover:bg-yellow-100";

    if (roomUsage.length === 0) return <p>Chưa có dữ liệu</p>;

    return (
      <table className={tableClass}>
        <thead>
          <tr>
            <th className={thClass}>Phòng số</th>
            <th className={thClass}>Số lần thuê</th>
          </tr>
        </thead>
        <tbody>
          {roomUsage.map((row, idx) => (
            <tr
              key={idx}
              className={`${idx % 2 === 0 ? trEven : trOdd} ${trHover}`}
            >
              <td className={tdClass}>{row.PhongSo}</td>
              <td className={tdClass}>{row.SoLanThue}</td>
            </tr>
          ))}
        </tbody>
      </table>
    );
  };

  return (
    <div className="p-6 bg-gray-50 min-h-screen">
      <h1 className="text-2xl font-bold mb-6 text-center">Báo cáo tổng hợp</h1>

      {/* Doanh thu */}
      <Card title="Doanh thu">
        <div className="mb-4">
          <label className="mr-2 font-semibold">Xem theo:</label>
          <select
            value={viewMode}
            onChange={(e) => setViewMode(e.target.value)}
            className="border rounded px-2 py-1"
          >
            <option value="monthly">Tháng</option>
            <option value="yearly">Năm</option>
          </select>
        </div>
        {renderRevenueTable()}
      </Card>

      {/* Top khách hàng */}
      <Card title="Top khách hàng">{renderTopCustomersTable()}</Card>

      {/* Công suất phòng */}
      <Card title="Công suất phòng">{renderRoomUsageTable()}</Card>
    </div>
  );
};

export default Report;
